### Обработчики событий — addEventListener, объект события, распространение, делегирование

```javascript
// --- Базовый addEventListener ---
const btn = document.querySelector('#btn');

function handleClick(event) {
  console.log(event.type);          // 'click'
  console.log(event.target);        // элемент, который был нажат (может быть дочерним)
  console.log(event.currentTarget); // элемент, к которому прикреплён слушатель
  event.preventDefault();           // остановить стандартное действие браузера
  event.stopPropagation();          // остановить всплытие к родительским элементам
}

btn.addEventListener('click', handleClick);
btn.removeEventListener('click', handleClick); // требует ТУ ЖЕ ссылку на функцию

// --- Одноразовый слушатель ---
btn.addEventListener('click', handleClick, { once: true });

// --- Распространение событий: захват → цель → всплытие ---
// Фаза захвата: событие движется вниз от window к цели
// Фаза цели: событие срабатывает на целевом элементе
// Фаза всплытия: событие движется вверх от цели к window

document.querySelector('#parent').addEventListener('click', (e) => {
  console.log('родитель нажат');
}, false); // false = фаза всплытия (по умолчанию)

document.querySelector('#child').addEventListener('click', (e) => {
  console.log('дочерний нажат');
  e.stopPropagation(); // предотвращает срабатывание 'родитель нажат'
});

// --- Делегирование событий: один слушатель для многих дочерних элементов ---
// Вместо добавления слушателя к каждому <li>, добавляем один к <ul>
document.querySelector('#list').addEventListener('click', (e) => {
  if (e.target.matches('li')) {
    console.log('Нажат пункт списка:', e.target.textContent);
  }
});

// Обрабатывает и динамически добавленные <li> — не нужно повторно прикреплять слушатели

// --- Распространённые типы событий ---
// Мышь: click, dblclick, mousedown, mouseup, mouseover, mouseleave, mousemove
// Клавиатура: keydown, keyup, keypress (устаревший)
// Форма: submit, change, input, focus, blur
// Документ: DOMContentLoaded (DOM разобран), load (все ресурсы загружены)
// Окно: resize, scroll, beforeunload
```

**Типичная ошибка на интервью:** `event.target` vs `event.currentTarget`:
- `target` = элемент, который пользователь фактически нажал (может быть дочерним)
- `currentTarget` = элемент со слушателем (всегда стабилен)

При делегировании событий используйте `currentTarget` когда имеете в виду «контейнер», и `target` когда имеете в виду «что было нажато».

answer.en:
### setTimeout, setInterval, and Scheduling in the Event Loop

`setTimeout` schedules a **one-time** macrotask after a minimum delay. `setInterval` schedules a **repeating** macrotask. Both return an ID for cancellation.

```javascript
// --- setTimeout basics ---
const id = setTimeout(() => {
  console.log('Runs once after ~200ms');
}, 200);

clearTimeout(id); // cancel before it fires

// --- setInterval basics ---
let count = 0;
const intervalId = setInterval(() => {
  count++;
  console.log(`Tick #${count}`);
  if (count === 3) clearInterval(intervalId); // stop after 3 ticks
}, 1000);

// --- setTimeout(fn, 0) does NOT mean "immediately" ---
console.log('A');
setTimeout(() => console.log('B'), 0);
Promise.resolve().then(() => console.log('C'));
console.log('D');
// Output: A D C B
// Reason: sync code first, then microtasks (Promise), then macrotasks (setTimeout)

// --- Minimum delay is not guaranteed ---
function blockFor(ms) {
  const start = Date.now();
  while (Date.now() - start < ms) {}
}

setTimeout(() => console.log('Timer fired'), 0);
blockFor(500); // blocks the thread for 500ms
// Timer fires after ~500ms, not 0ms

// --- setInterval drift problem ---
// If the callback takes longer than the interval, tasks queue up
// Alternative: recursive setTimeout for self-scheduling
function repeat(fn, delay) {
  setTimeout(function tick() {
    fn();
    setTimeout(tick, delay); // schedule next only after current completes
  }, delay);
}
```

**Key differences:**
| | `setTimeout` | `setInterval` |
|--|--|--|
| Fires | Once | Repeatedly |
| Drift | N/A | Yes — if callback is slow, intervals drift |
| Cancellation | `clearTimeout(id)` | `clearInterval(id)` |

**Common interview trap:** `setTimeout(fn, 0)` puts `fn` in the **macrotask** queue. Promises (`.then`) go to the **microtask** queue. Microtasks drain completely before any macrotask runs — so a resolved Promise always beats a 0ms timeout.

answer.ru:
### setTimeout, setInterval и планирование в Event Loop

`setTimeout` планирует **однократную** макрозадачу после минимальной задержки. `setInterval` планирует **повторяющуюся** макрозадачу. Оба возвращают ID для отмены.

```javascript
// --- Основы setTimeout ---
const id = setTimeout(() => {
  console.log('Выполняется один раз после ~200ms');
}, 200);

clearTimeout(id); // отмена до срабатывания

// --- Основы setInterval ---
let count = 0;
const intervalId = setInterval(() => {
  count++;
  console.log(`Тик #${count}`);
  if (count === 3) clearInterval(intervalId); // остановка после 3 тиков
}, 1000);

// --- setTimeout(fn, 0) НЕ означает «немедленно» ---
console.log('A');
setTimeout(() => console.log('B'), 0);
Promise.resolve().then(() => console.log('C'));
console.log('D');
// Вывод: A D C B
// Причина: сначала синхронный код, затем микрозадачи (Promise), затем макрозадачи (setTimeout)

// --- Минимальная задержка не гарантирована ---
function blockFor(ms) {
  const start = Date.now();
  while (Date.now() - start < ms) {}
}

setTimeout(() => console.log('Таймер сработал'), 0);
blockFor(500); // блокирует поток на 500ms
// Таймер срабатывает через ~500ms, не 0ms

// --- Проблема дрейфа setInterval ---
// Если callback занимает больше времени, чем интервал, задачи накапливаются
// Альтернатива: рекурсивный setTimeout для самопланирования
function repeat(fn, delay) {
  setTimeout(function tick() {
    fn();
    setTimeout(tick, delay); // планируем следующий только после завершения текущего
  }, delay);
}
```

**Ключевые различия:**
| | `setTimeout` | `setInterval` |
|--|--|--|
| Срабатывает | Один раз | Многократно |
| Дрейф | Нет | Да — если callback медленный, интервалы смещаются |
| Отмена | `clearTimeout(id)` | `clearInterval(id)` |

**Типичная ошибка на интервью:** `setTimeout(fn, 0)` помещает `fn` в очередь **макрозадач**. Promise (`.then`) попадают в очередь **микрозадач**. Микрозадачи полностью опустошаются до выполнения любой макрозадачи — поэтому resolved Promise всегда выполняется раньше 0ms таймаута.

answer.en:
### Callbacks and Callback Hell

A **callback** is a function passed as an argument to another function, invoked when an asynchronous operation completes. The callback-based pattern was the original way to handle async work in JavaScript before Promises.

**Callback hell** (also "pyramid of doom") emerges when sequential async operations nest callbacks inside callbacks, making code nearly unmaintainable.

```javascript
// Single callback — fine
fs.readFile('config.json', 'utf8', (err, data) => {
  if (err) throw err;
  console.log(data);
});

// Callback hell — 3 dependent operations
getUser(userId, (err, user) => {
  if (err) return handleError(err);

  getUserPosts(user.id, (err, posts) => {
    if (err) return handleError(err);

    getPostComments(posts[0].id, (err, comments) => {
      if (err) return handleError(err);

      // Finally have comments
      console.log(comments);
      // What if we need a 4th operation? Indent grows forever...
    });
  });
});

// Solution 1: Named functions (flatten the pyramid)
function onComments(err, comments) {
  if (err) return handleError(err);
  console.log(comments);
}

function onPosts(err, posts) {
  if (err) return handleError(err);
  getPostComments(posts[0].id, onComments);
}

function onUser(err, user) {
  if (err) return handleError(err);
  getUserPosts(user.id, onPosts);
}

getUser(userId, onUser);

// Solution 2: Promises + .then() chaining
getUser(userId)
  .then(user => getUserPosts(user.id))
  .then(posts => getPostComments(posts[0].id))
  .then(comments => console.log(comments))
  .catch(handleError);

// Solution 3: async/await (modern, most readable)
async function loadComments(userId) {
  try {
    const user = await getUser(userId);
    const posts = await getUserPosts(user.id);
    const comments = await getPostComments(posts[0].id);
    console.log(comments);
  } catch (err) {
    handleError(err);
  }
}
```

**Common interview trap:** Callbacks themselves are not bad — they're used everywhere (array methods like `forEach`, event listeners, `setTimeout`). The problem is *nested* callbacks for sequential async operations, because error handling must be repeated at every level and control flow becomes impossible to follow. Promises and `async/await` solve nesting — not callbacks in general.

answer.ru:
### Функции обратного вызова и ад обратных вызовов

**Callback** (функция обратного вызова) — это функция, передаваемая в качестве аргумента другой функции, вызываемая по завершению асинхронной операции. Паттерн на основе callback'ов был первоначальным способом обработки async-работы в JavaScript до появления Promise.

**Ад обратных вызовов** («пирамида судьбы») возникает, когда последовательные асинхронные операции вкладывают callback'и в callback'и, делая код практически невозможным для поддержки.

```javascript
// Один callback — нормально
fs.readFile('config.json', 'utf8', (err, data) => {
  if (err) throw err;
  console.log(data);
});

// Ад обратных вызовов — 3 зависимые операции
getUser(userId, (err, user) => {
  if (err) return handleError(err);

  getUserPosts(user.id, (err, posts) => {
    if (err) return handleError(err);

    getPostComments(posts[0].id, (err, comments) => {
      if (err) return handleError(err);

      // Наконец-то получили комментарии
      console.log(comments);
      // Если нужна 4-я операция, отступ растёт бесконечно...
    });
  });
});

// Решение 1: Именованные функции (выравнивание пирамиды)
function onComments(err, comments) {
  if (err) return handleError(err);
  console.log(comments);
}

function onPosts(err, posts) {
  if (err) return handleError(err);
  getPostComments(posts[0].id, onComments);
}

function onUser(err, user) {
  if (err) return handleError(err);
  getUserPosts(user.id, onPosts);
}

getUser(userId, onUser);

// Решение 2: Promise + цепочка .then()
getUser(userId)
  .then(user => getUserPosts(user.id))
  .then(posts => getPostComments(posts[0].id))
  .then(comments => console.log(comments))
  .catch(handleError);

// Решение 3: async/await (современно, наиболее читаемо)
async function loadComments(userId) {
  try {
    const user = await getUser(userId);
    const posts = await getUserPosts(user.id);
    const comments = await getPostComments(posts[0].id);
    console.log(comments);
  } catch (err) {
    handleError(err);
  }
}
```

**Типичная ошибка на интервью:** Callback'и сами по себе не плохи — они используются повсюду (`forEach`, обработчики событий, `setTimeout`). Проблема — *вложенные* callback'и для последовательных асинхронных операций, потому что обработка ошибок должна повторяться на каждом уровне, а управление потоком становится невозможным. Promise и `async/await` решают проблему вложенности, а не callback'и в целом.

answer.en:
### Promises — State Machine, Chaining, and Static Methods

A **Promise** is an object representing the eventual result of an asynchronous operation. It acts as a state machine with three states:

- **pending** — initial state, operation not complete
- **fulfilled** — operation succeeded, result available
- **rejected** — operation failed, reason available

Once settled (fulfilled or rejected), a promise is **immutable** — it cannot change state again.

```javascript
// Creating a promise
const p = new Promise((resolve, reject) => {
  // executor runs synchronously
  setTimeout(() => {
    const success = Math.random() > 0.5;
    if (success) {
      resolve({ data: 'ok' });  // transitions to fulfilled
    } else {
      reject(new Error('failed')); // transitions to rejected
    }
  }, 100);
});

// Consuming a promise
p
  .then(result => {           // called if fulfilled
    console.log(result.data);
    return 'chained value';   // .then returns a NEW promise
  })
  .then(val => console.log(val)) // receives 'chained value'
  .catch(err => console.error(err.message)) // catches rejections from any .then above
  .finally(() => console.log('always runs'));

// Static methods
const p1 = Promise.resolve(1);
const p2 = Promise.resolve(2);
const p3 = Promise.reject(new Error('oops'));

// Promise.all: waits for ALL to fulfill; rejects on first rejection
Promise.all([p1, p2]).then(([a, b]) => console.log(a, b)); // 1 2
Promise.all([p1, p3]).catch(e => console.log(e.message));  // 'oops'

// Promise.allSettled: waits for ALL, never rejects, returns array of status objects
Promise.allSettled([p1, p3]).then(results => {
  // [{status: 'fulfilled', value: 1}, {status: 'rejected', reason: Error}]
  results.forEach(r => console.log(r.status));
});

// Promise.race: resolves/rejects with whichever settles first
Promise.race([p1, p2]).then(val => console.log(val)); // 1 or 2

// Promise.any: resolves with first fulfilled; rejects only if ALL reject (AggregateError)
Promise.any([p3, p1]).then(val => console.log(val)); // 1
```

**Common interview trap:** Unhandled promise rejections are a common production bug. If you don't attach a `.catch()` (or `try/catch` with `await`), the rejection silently fails in older Node and causes a process crash warning in modern Node. Also, `Promise.all` **rejects fast** — if one promise rejects, you lose all other results. Use `Promise.allSettled` when you need results from all, including failed ones.

answer.ru:
### Promise — Конечный автомат, цепочки и статические методы

**Promise** — объект, представляющий итоговый результат асинхронной операции. Работает как конечный автомат с тремя состояниями:

- **pending** — начальное состояние, операция не завершена
- **fulfilled** — операция успешна, результат доступен
- **rejected** — операция провалилась, причина доступна

После перехода в settled-состояние (fulfilled или rejected) промис **неизменяем** — больше не может менять состояние.

```javascript
// Создание промиса
const p = new Promise((resolve, reject) => {
  // executor выполняется синхронно
  setTimeout(() => {
    const success = Math.random() > 0.5;
    if (success) {
      resolve({ data: 'ok' });   // переходит в fulfilled
    } else {
      reject(new Error('failed')); // переходит в rejected
    }
  }, 100);
});

// Потребление промиса
p
  .then(result => {           // вызывается при fulfilled
    console.log(result.data);
    return 'chained value';   // .then возвращает НОВЫЙ промис
  })
  .then(val => console.log(val)) // получает 'chained value'
  .catch(err => console.error(err.message)) // ловит отказы из любого .then выше
  .finally(() => console.log('всегда выполняется'));

// Статические методы
const p1 = Promise.resolve(1);
const p2 = Promise.resolve(2);
const p3 = Promise.reject(new Error('упс'));

// Promise.all: ждёт ВСЕ fulfilled; отклоняется при первом reject
Promise.all([p1, p2]).then(([a, b]) => console.log(a, b)); // 1 2
Promise.all([p1, p3]).catch(e => console.log(e.message));  // 'упс'

// Promise.allSettled: ждёт ВСЕ, никогда не отклоняется, возвращает статусы
Promise.allSettled([p1, p3]).then(results => {
  // [{status: 'fulfilled', value: 1}, {status: 'rejected', reason: Error}]
  results.forEach(r => console.log(r.status));
});

// Promise.race: resolves/rejects с тем, что первым завершится
Promise.race([p1, p2]).then(val => console.log(val)); // 1 или 2

// Promise.any: resolves с первым fulfilled; отклоняется только если ВСЕ отклонены (AggregateError)
Promise.any([p3, p1]).then(val => console.log(val)); // 1
```

**Типичная ошибка на интервью:** Необработанные отказы промисов — распространённый баг на проде. Без `.catch()` (или `try/catch` с `await`) отказ тихо провалится. Также `Promise.all` **отказывает быстро** — если один промис отклоняется, теряются все остальные результаты. Используйте `Promise.allSettled`, когда нужны результаты всех, включая упавшие.

answer.en:
### null vs undefined — Intentional vs Accidental Absence

Both represent "no value" but have different semantics and use cases.

**`undefined`** — the runtime's signal that a value is *missing by accident*:
- Uninitialized variable
- Missing function argument
- Accessing a non-existent object property
- Implicit function return

**`null`** — a developer's explicit signal that a value is *intentionally absent*:
- "I know there's no user here"
- Database/API returning "no record"
- Clearing a reference

```javascript
// undefined — set by the runtime
let x;
console.log(x);                  // undefined — declared but not assigned

function greet(name) {
  return name;
}
console.log(greet());            // undefined — argument not provided

const obj = { a: 1 };
console.log(obj.b);              // undefined — property doesn't exist
console.log(obj.b?.c);          // undefined — optional chaining short-circuits

function fn() { /* no return */ }
console.log(fn());               // undefined — implicit return

// null — set by the developer
let currentUser = null;          // explicitly: no user yet
currentUser = { name: 'Alice' }; // now we have a user
currentUser = null;              // explicitly: logged out, no user

// Equality checks
console.log(null == undefined);  // true  (loose — handy for "either is absent")
console.log(null === undefined); // false (strict)
console.log(null == 0);         // false (null only loosely equals undefined)
console.log(null == false);     // false

// Practical null check patterns
const value = null;

// Nullish coalescing (null or undefined → use default)
const display = value ?? 'No value'; // 'No value'
// vs OR (any falsy → use default, including 0, '', false)
const display2 = value || 'No value'; // 'No value' — BUT 0 || 'default' = 'default'!

// Optional chaining
const city = currentUser?.address?.city; // undefined (not an error)

// typeof quirks
console.log(typeof undefined); // 'undefined'
console.log(typeof null);      // 'object' — 30-year-old JS bug; null is NOT an object
```

**Common interview trap:** Always use `value === null` or `value === undefined` for strict checks. Use `value == null` (loose) only as a shorthand for "is this null OR undefined". The nullish coalescing operator `??` is usually preferable to `||` for defaults, because `??` only triggers on `null`/`undefined`, while `||` triggers on any falsy value (including `0`, `''`, `false`).

answer.ru:
### null vs undefined — Намеренное vs Случайное отсутствие

Оба представляют «нет значения», но имеют разную семантику и случаи использования.

**`undefined`** — сигнал среды выполнения, что значение *отсутствует случайно*:
- Неинициализированная переменная
- Отсутствующий аргумент функции
- Обращение к несуществующему свойству объекта
- Неявный возврат функции

**`null`** — явный сигнал разработчика, что значение *намеренно отсутствует*:
- «Я знаю, что здесь нет пользователя»
- БД/API вернул «нет записи»
- Очистка ссылки

```javascript
// undefined — устанавливается средой выполнения
let x;
console.log(x);                  // undefined — объявлена, но не присвоена

function greet(name) {
  return name;
}
console.log(greet());            // undefined — аргумент не передан

const obj = { a: 1 };
console.log(obj.b);              // undefined — свойство не существует
console.log(obj.b?.c);          // undefined — опциональная цепочка замыкает путь

function fn() { /* нет return */ }
console.log(fn());               // undefined — неявный возврат

// null — устанавливается разработчиком
let currentUser = null;          // явно: пока нет пользователя
currentUser = { name: 'Alice' }; // теперь есть пользователь
currentUser = null;              // явно: вышел из системы, пользователя нет

// Проверки на равенство
console.log(null == undefined);  // true  (нестрогое — удобно для «отсутствует любое»)
console.log(null === undefined); // false (строгое)
console.log(null == 0);         // false (null нестрого равен только undefined)
console.log(null == false);     // false

// Паттерны проверки на null
const value = null;

// Оператор нулевого слияния (null или undefined → использовать умолчание)
const display = value ?? 'Нет значения'; // 'Нет значения'
// vs OR (любое ложное → умолчание, включая 0, '', false)
const display2 = value || 'Нет значения'; // 'Нет значения' — НО 0 || 'def' = 'def'!

// Опциональная цепочка
const city = currentUser?.address?.city; // undefined (не ошибка)

// Особенности typeof
console.log(typeof undefined); // 'undefined'
console.log(typeof null);      // 'object' — 30-летний баг JS; null НЕ является объектом
```

**Типичная ошибка на интервью:** Используйте `value === null` или `value === undefined` для строгих проверок. `value == null` (нестрогое) — только как сокращение для «это null ИЛИ undefined». Оператор нулевого слияния `??` обычно предпочтительнее `||` для значений по умолчанию, потому что `??` срабатывает только на `null`/`undefined`, а `||` — на любое ложное значение (включая `0`, `''`, `false`).

answer.en:
### Template Literals — Interpolation, Multiline, and Tagged Templates

Template literals use backtick (`````) delimiters and support three features regular strings don't: **interpolation**, **multiline**, and **tagged templates**.

```javascript
// --- Basic interpolation ---
const name = 'Alice';
const age = 28;

// Old way
const old = 'Hello, ' + name + '! You are ' + age + ' years old.';

// Template literal — any JS expression is valid inside ${}
const modern = `Hello, ${name}! You are ${age} years old.`;
console.log(`2 + 2 = ${2 + 2}`);             // '2 + 2 = 4'
console.log(`Is admin: ${age > 18 ? 'yes' : 'no'}`); // 'Is admin: yes'
console.log(`Reversed: ${name.split('').reverse().join('')}`); // 'ecilA'

// --- Multiline strings ---
const html = `
  <div class="card">
    <h2>${name}</h2>
    <p>Age: ${age}</p>
  </div>
`;
// Preserves actual newlines and indentation

// Old way required \n
const oldHtml = '<div>\n  <h2>' + name + '</h2>\n</div>';

// --- Tagged template literals ---
// A tag is a function: (strings, ...values) => result
function highlight(strings, ...values) {
  return strings.reduce((result, str, i) => {
    const value = values[i - 1];
    return result + `<mark>${value}</mark>` + str;
  });
}

const item = 'JavaScript';
const score = 95;
const message = highlight`You scored ${score} on ${item} quiz!`;
// 'You scored <mark>95</mark> on <mark>JavaScript</mark> quiz!'

// Real-world use: SQL tagged template (prevents SQL injection)
// Many DB libraries use this pattern:
// sql`SELECT * FROM users WHERE id = ${userId}`
// The tag function handles escaping/parameterization

// String.raw — built-in tag, disables escape sequences
const path = String.raw`C:\Users\Alice\Documents`;
console.log(path); // C:\Users\Alice\Documents (backslashes preserved)
```

**Common interview trap:** Template literals preserve **all** whitespace inside them, including leading spaces on each line. This means a multi-line template literal indented with 4 spaces will include those 4 spaces in the output string. This can cause unexpected whitespace in generated HTML or SQL. Also, expressions inside `${}` can call functions, access properties, or compute any value — not just variables.

