### Closures — Memoization and Memory Implications

```javascript
// Memoization: cache expensive function results using a closure
function memoize(fn) {
  const cache = new Map(); // closed over by the returned function
  return function(...args) {
    const key = JSON.stringify(args);
    if (cache.has(key)) {
      console.log('cache hit');
      return cache.get(key);
    }
    const result = fn.apply(this, args);
    cache.set(key, result);
    return result;
  };
}

function expensiveCalc(n) {
  let sum = 0;
  for (let i = 0; i <= n; i++) sum += i;
  return sum;
}

const memoCalc = memoize(expensiveCalc);
memoCalc(1000); // computes
memoCalc(1000); // 'cache hit'
memoCalc(2000); // computes (different args)

// --- Partial application using closures ---
function multiply(a, b) { return a * b; }

function partial(fn, ...presetArgs) {
  return function(...laterArgs) {
    return fn(...presetArgs, ...laterArgs);
  };
}

const double = partial(multiply, 2);
const triple = partial(multiply, 3);

console.log(double(5));  // 10
console.log(triple(5)); // 15

// --- Memory leak risk ---
const leaks = [];

function leak() {
  const bigArray = new Array(10_000).fill('data'); // large allocation
  leaks.push(() => bigArray.length); // closure keeps bigArray alive!
}

leak();
// bigArray won't be GC'd because the closure in 'leaks' references it

// Solution: use WeakRef if you want the closure but allow GC
const weakLeaks = [];
function noLeak() {
  const bigArray = new Array(10_000).fill('data');
  const ref = new WeakRef(bigArray);
  weakLeaks.push(() => ref.deref()?.length ?? 0); // won't prevent GC
}
```

**Common interview trap:** A closure keeps its entire outer scope alive for as long as the closure itself is referenced. If you create closures inside event listeners and never remove them, all the variables they captured remain in memory. This is a common source of memory leaks in long-running SPAs. The fix is to either remove event listeners when components unmount, or use `WeakRef` when you want GC-eligible references.

