### Замыкания — Паттерн Event Emitter

Более сложное реальное применение замыканий: создание типизированного event emitter, где и реестр событий, и списки слушателей приватны.

```javascript
function createEventEmitter() {
  // И 'listeners', и всё его содержимое приватны для этого замыкания
  const listeners = {};

  return {
    on(event, fn) {
      if (!listeners[event]) listeners[event] = [];
      listeners[event].push(fn);
      // Возвращает функцию отписки — само замыкание над 'event' и 'fn'
      return () => this.off(event, fn);
    },
    off(event, fn) {
      if (!listeners[event]) return;
      listeners[event] = listeners[event].filter(f => f !== fn);
    },
    emit(event, ...args) {
      if (!listeners[event]) return;
      listeners[event].forEach(fn => fn(...args));
    },
    once(event, fn) {
      const wrapper = (...args) => {
        fn(...args);
        this.off(event, wrapper); // удаляет себя после первого вызова
      };
      this.on(event, wrapper);
    }
  };
}

const emitter = createEventEmitter();

const unsubscribe = emitter.on('data', (payload) => {
  console.log('получено:', payload);
});

emitter.once('connect', () => {
  console.log('подключено — срабатывает только раз');
});

emitter.emit('data', { id: 1, value: 42 }); // 'получено: { id: 1, value: 42 }'
emitter.emit('connect'); // 'подключено — срабатывает только раз'
emitter.emit('connect'); // ничего — слушатель удалён

unsubscribe(); // прекратить слушать 'data'
emitter.emit('data', { id: 2 }); // ничего — отписан

// 'listeners' недоступен снаружи — настоящая приватность
console.log(emitter.listeners); // undefined
```

**Типичная ошибка на интервью:** Метод `once` создаёт **замыкание-обёртку**, ссылающееся на оригинальную `fn` и использующее `this.off` для самоудаления. Ключевое понимание: каждый вызов `on` может вернуть другую функцию отписки, потому что каждый вызов создаёт собственное замыкание — не ту же ссылку. Если передать `fn` напрямую в `off`, метод `once` не сработает, потому что `off` ищет функцию `wrapper`, а не `fn`.

answer.en:
### Promise.all vs allSettled — Practical Decision Guide

Choosing between them depends on whether partial failure is acceptable.

```javascript
// Use Promise.all when ALL results are required — fail fast
async function loadDashboard(userId) {
  // If any fails, the entire dashboard should fail
  const [user, permissions, settings] = await Promise.all([
    fetchUser(userId),
    fetchPermissions(userId),
    fetchSettings(userId)
  ]);
  return { user, permissions, settings };
}

// Use Promise.allSettled when partial results are OK — report all statuses
async function syncWithThirdParties(webhooks) {
  const results = await Promise.allSettled(
    webhooks.map(url => fetch(url, { method: 'POST', body: payload }))
  );

  const succeeded = results.filter(r => r.status === 'fulfilled').length;
  const failed = results
    .filter(r => r.status === 'rejected')
    .map(r => r.reason.message);

  return { succeeded, failed, total: webhooks.length };
}

// Promise.race: first one wins (useful for timeouts)
async function fetchWithTimeout(url, ms) {
  const timeout = new Promise((_, reject) =>
    setTimeout(() => reject(new Error(`Timeout after ${ms}ms`)), ms)
  );
  return Promise.race([fetch(url).then(r => r.json()), timeout]);
}

// Promise.any: first FULFILLED wins (ignores rejections)
async function fetchFromFastestMirror(mirrors) {
  try {
    return await Promise.any(mirrors.map(url => fetch(url).then(r => r.json())));
  } catch (err) {
    // AggregateError — only if ALL mirrors failed
    throw new Error('All mirrors unavailable');
  }
}

// Comparison table
// Promise.all       — all fulfilled → values; any rejected → rejects immediately
// Promise.allSettled — all settled  → [{status, value/reason}]; never rejects
// Promise.race       — first settled → that value or error
// Promise.any        — first fulfilled → value; all rejected → AggregateError
```

**Common interview trap:** `Promise.all` with an empty array resolves immediately with `[]`. `Promise.race` with an empty array **never settles** — it returns a Promise that stays pending forever. Also, in `allSettled`, fulfilled results have `{ status: 'fulfilled', value }` and rejected have `{ status: 'rejected', reason }` — not `error`.

