    .then(r => r.json())
    .then(data => {
      if (!data.id) throw new Error('Отсутствует id');
      return data;
    });
}
// Стек ошибки: "Error: Отсутствует id" в anonymous — тяжело отследить

// async/await: стек вызовов называет async-функцию
