console.log(config.apiUrl); // работает на верхнем уровне модуля

// --- async IIFE для немедленного вызова ---
(async () => {
  const result = await someAsyncOperation();
  console.log(result);
})();

// --- Ловушка: последовательное vs конкурентное ---
// Выполняются последовательно (2 секунды если каждый занимает 1с)
async function sequential() {
  const a = await fetchA(); // ждёт A
  const b = await fetchB(); // затем ждёт B
  return [a, b];
}

// Выполняются конкурентно (1 секунда)
async function concurrent() {
  const [a, b] = await Promise.all([fetchA(), fetchB()]);
  return [a, b];
}

// Запускаются конкурентно, ожидаются последовательно — ВЕРНО для конкурентности!
async function startedConcurrentlyAwaitedSequentially() {
  const promiseA = fetchA(); // запущен
  const promiseB = fetchB(); // запущен (ещё не awaited)
  const a = await promiseA; // awaited по порядку — всё равно конкурентно!
  const b = await promiseB;
  return [a, b];
}
// Выполняется конкурентно — оба Promise в полёте до первого await

// --- async-функция всегда возвращает Promise ---
async function returnPrimitive() {
  return 42;
}
returnPrimitive().then(v => console.log(v)); // 42 — обёрнут в Promise
console.log(returnPrimitive() instanceof Promise); // true
```

**Типичная ошибка на интервью:** Запуск обеих функций возвращающих Promise затем `await` по очереди — ЭТО конкурентное выполнение (оба запускаются немедленно). Проблема возникает только когда `await` выполняется до запуска второй операции. Многие разработчики ошибочно считают `const a = await fetchA(); const b = await fetchB();` тем же что `await Promise.all([fetchA(), fetchB()])` — это НЕ так. Первое — последовательно; `Promise.all` — действительно параллельно.

