export function increment() { count++; }

// consumer.mjs
import { count, increment } from './counter.mjs';
console.log(count); // 0
increment();
console.log(count); // 1 — экспорты ESM — ЖИВЫЕ ПРИВЯЗКИ

// counter.cjs — CJS
module.exports = { count: 0, increment() { this.count++; } };

// consumer.cjs
const { count, increment } = require('./counter.cjs');
console.log(count); // 0
increment.call(module.exports); // нужно вызывать на объекте exports
console.log(count); // всё ещё 0 — CJS копирует ЗНАЧЕНИЕ при require!

// --- Совместимость ---
// ESM может импортировать CJS (только default import):
import cjsModule from './legacy.cjs'; // получает module.exports как default
// import { named } from './legacy.cjs'; // может работать в Node 20+, но не гарантировано

// CJS не может синхронно require ESM:
// const esm = require('./modern.mjs'); // ERR_REQUIRE_ESM
// Нужен динамический import:
(async () => {
  const { add } = await import('./math.mjs'); // работает
})();

// --- Dual package: публикация для обоих ---
// package.json
// {
//   "exports": {
//     ".": {
//       "import": "./dist/index.mjs",
//       "require": "./dist/index.cjs"
//     }
//   }
// }
// Dual package hazard: если обе версии загружены, существуют два отдельных экземпляра!
// Состояние в CJS не разделяется с ESM версией

// --- Когда использовать каждый ---
// CLI-инструменты Node.js, legacy кодовые базы: CJS (проще, без настройки)
// Современные веб-приложения, собранный код, новые пакеты: ESM (tree-shaking, живые привязки)
// Node.js >= 22 поддерживает ESM нативно с .mjs или "type": "module" в package.json
```

**Типичная ошибка на интервью:** `import` в начале файла **поднимается** — все статические импорты обрабатываются до выполнения какого-либо кода. Поэтому нельзя иметь статический `import` внутри блока `if` (SyntaxError). Для условных импортов используйте динамический `import()` возвращающий Promise. Также круговые зависимости в CJS возвращают **частично заполненный** объект (то что было экспортировано до достижения цикла), а ESM обрабатывает циклические зависимости через живые привязки (привязка существует, но может быть `undefined` до завершения инициализации).

answer.en:
### Microtask Queue Draining — The Full Mental Model

The event loop processes tasks one at a time. After each task (macrotask), it **fully drains** the microtask queue — including any new microtasks scheduled by the running microtasks.

```javascript
console.log('1: sync');

setTimeout(() => console.log('5: macrotask'), 0);

Promise.resolve()
  .then(() => {
    console.log('3: microtask 1');
    // Scheduling a microtask FROM a microtask:
    Promise.resolve().then(() => console.log('4: nested microtask'));
  });

console.log('2: sync');

// Output:
// 1: sync
// 2: sync
// 3: microtask 1       ← microtask queue starts draining
// 4: nested microtask  ← nested microtask runs BEFORE macrotask
// 5: macrotask         ← only now does the macrotask run

// queueMicrotask is the low-level API (no Promise wrapper overhead)
queueMicrotask(() => console.log('also a microtask'));

// Practical consequence: infinite microtask loop STARVES the render!
function dangerousLoop() {
  Promise.resolve().then(dangerousLoop); // never lets macrotasks run
}
// dangerousLoop(); // would freeze the browser
```

**Event loop cycle (simplified):**
1. Pick one macrotask from the task queue (setTimeout, I/O, user events)
2. Execute it
3. Drain the entire microtask queue (including newly added ones)
4. If the browser has time → render update
5. Go to step 1

**Common interview trap:** The microtask queue is drained **completely** after each task, not just one microtask per cycle. This means if a microtask schedules another microtask, that new one also runs before the next macrotask. A chain of `.then().then().then()` all execute before `setTimeout(fn, 0)` — even if the `setTimeout` was registered first.

answer.ru:
### Очистка очереди микротасок — Полная ментальная модель

Event loop обрабатывает задачи по одной. После каждой задачи (макротаски) он **полностью опустошает** очередь микротасок — включая новые микротаски, запланированные выполняющимися микротасками.

```javascript
console.log('1: sync');

setTimeout(() => console.log('5: macrotask'), 0);

Promise.resolve()
  .then(() => {
    console.log('3: microtask 1');
    // Планируем микротаску ИЗ микротаски:
    Promise.resolve().then(() => console.log('4: nested microtask'));
  });

console.log('2: sync');

// Вывод:
// 1: sync
// 2: sync
// 3: microtask 1       ← начало очистки очереди микротасок
// 4: nested microtask  ← вложенная микротаска выполняется ДО макротаски
// 5: macrotask         ← только теперь выполняется макротаска

// queueMicrotask — низкоуровневый API (без накладных расходов Promise)
queueMicrotask(() => console.log('тоже микротаска'));

// Практическое следствие: бесконечный цикл микротасок БЛОКИРУЕТ рендер!
function dangerousLoop() {
  Promise.resolve().then(dangerousLoop); // не даёт макротаскам выполниться
}
// dangerousLoop(); // заморозит браузер
```

**Цикл event loop (упрощённо):**
1. Берём одну макротаску из очереди (setTimeout, I/O, события пользователя)
2. Выполняем её
3. Полностью очищаем очередь микротасок (включая вновь добавленные)
4. Если у браузера есть время → обновление рендера
5. Переходим к шагу 1

**Типичная ошибка на интервью:** Очередь микротасок очищается **полностью** после каждой задачи, а не по одной микротаске за цикл. Это означает, что если микротаска планирует другую микротаску, та тоже выполнится до следующей макротаски. Цепочка `.then().then().then()` вся выполняется до `setTimeout(fn, 0)` — даже если `setTimeout` был зарегистрирован раньше.

answer.en:
### Generators — Two-Way Communication and the Full Protocol

Generators are coroutines: execution can be paused (`yield`) and resumed, with values flowing both ways.

```javascript
function* calculator() {
  let result = 0;
  while (true) {
    // yield sends a value out; the value passed to .next() comes back in
    const input = yield result;
    if (input === null) return result; // .return() or null breaks the loop
    result += input;
  }
}

const calc = calculator();
console.log(calc.next().value);    // 0 — initial yield
console.log(calc.next(5).value);   // 5 — sent 5 in, got 5 back
console.log(calc.next(3).value);   // 8 — sent 3 in, got 8 back
console.log(calc.next(null).value); // 8 — return value (done: true)

// --- Generator methods ---
function* demo() {
  try {
    const x = yield 1;
    yield x * 2;
  } catch (e) {
    yield `caught: ${e.message}`;
  }
}

const g = demo();
console.log(g.next());        // { value: 1, done: false }
console.log(g.throw(new Error('oops'))); // { value: 'caught: oops', done: false }
console.log(g.next());        // { value: undefined, done: true }

// --- yield* delegates to another iterable ---
function* inner() { yield 2; yield 3; }
function* outer() {
  yield 1;
  yield* inner(); // flattens inner into outer's sequence
  yield 4;
}
console.log([...outer()]); // [1, 2, 3, 4]

// --- Async generators (ES2018) ---
async function* paginate(url) {
  let page = 1;
  while (true) {
    const res = await fetch(`${url}?page=${page}`);
    const data = await res.json();
    if (data.items.length === 0) return;
    yield data.items; // yields an array per page
    page++;
  }
}

for await (const items of paginate('/api/posts')) {
  console.log(items); // one page at a time, on demand
}
```

**Common interview trap:** The value passed to the **first** `.next(value)` call is **always ignored** — there's no `yield` on the left-hand side to receive it yet. Two-way communication starts from the second call. Also, `for...of` calls `.return()` on early `break`, which triggers the `finally` block inside the generator.

answer.ru:
### Генераторы — Двусторонняя коммуникация и полный протокол

Генераторы — это корутины: выполнение можно приостановить (`yield`) и возобновить, с потоком значений в обе стороны.

```javascript
function* calculator() {
  let result = 0;
  while (true) {
    // yield отправляет значение наружу; значение переданное в .next() возвращается внутрь
    const input = yield result;
    if (input === null) return result; // .return() или null прерывает цикл
    result += input;
  }
}

const calc = calculator();
console.log(calc.next().value);    // 0 — первоначальный yield
console.log(calc.next(5).value);   // 5 — отправили 5 внутрь, получили 5 обратно
console.log(calc.next(3).value);   // 8 — отправили 3 внутрь, получили 8 обратно
console.log(calc.next(null).value); // 8 — возвращаемое значение (done: true)

// --- Методы генератора ---
function* demo() {
  try {
    const x = yield 1;
    yield x * 2;
  } catch (e) {
    yield `поймали: ${e.message}`;
  }
}

const g = demo();
console.log(g.next());        // { value: 1, done: false }
console.log(g.throw(new Error('ошибка'))); // { value: 'поймали: ошибка', done: false }
console.log(g.next());        // { value: undefined, done: true }

// --- yield* делегирует другому итерируемому ---
function* inner() { yield 2; yield 3; }
function* outer() {
  yield 1;
  yield* inner(); // разворачивает inner в последовательность outer
  yield 4;
}
console.log([...outer()]); // [1, 2, 3, 4]

// --- Асинхронные генераторы (ES2018) ---
async function* paginate(url) {
  let page = 1;
  while (true) {
    const res = await fetch(`${url}?page=${page}`);
    const data = await res.json();
    if (data.items.length === 0) return;
    yield data.items; // возвращает массив на страницу
    page++;
  }
}

for await (const items of paginate('/api/posts')) {
  console.log(items); // одна страница за раз, по требованию
}
```

**Типичная ошибка на интервью:** Значение переданное в **первый** вызов `.next(value)` **всегда игнорируется** — слева от `yield` ещё нет ничего что могло бы его получить. Двусторонняя коммуникация начинается со второго вызова. Также `for...of` вызывает `.return()` при раннем `break`, что запускает блок `finally` внутри генератора.

answer.en:
### Proxy with Reflect for Validation

Proxy intercepts operations while Reflect provides a consistent API that mirrors the same operations, ensuring proper `this` binding and handling edge cases. This pattern allows validation logic before assignment.

```typescript
const user = new Proxy({}, {
  set(target, prop, value) {
    if (prop === 'age' && typeof value !== 'number') {
      throw new TypeError('Age must be a number');
    }
    return Reflect.set(target, prop, value);
  }
});

user.age = 25; // OK
user.age = '25'; // TypeError
```

**Common interview trap:** Using direct assignment like `target[prop] = value` instead of `Reflect.set()` bypasses descriptor traps and ignores property flags.

answer.ru:
### Proxy с Reflect для валидации

Proxy перехватывает операции, а Reflect предоставляет согласованный API, который зеркалирует те же операции, обеспечивая правильное связывание `this` и обработку граничных случаев. Этот паттерн позволяет логику валидации перед присваиванием.

```typescript
const user = new Proxy({}, {
  set(target, prop, value) {
    if (prop === 'age' && typeof value !== 'number') {
      throw new TypeError('Age must be a number');
    }
    return Reflect.set(target, prop, value);
  }
});

user.age = 25; // OK
user.age = '25'; // TypeError
```

**Типичная ошибка:** Использование прямого присваивания `target[prop] = value` вместо `Reflect.set()` обходит ловушки дескрипторов и игнорирует флаги свойств.

answer.en:
### WeakMap and WeakRef for Memory Management

WeakMap holds weak references to keys (allowing garbage collection when no other references exist) and is useful for private data storage. WeakRef creates explicit weak references to objects. Use them when you want data to be automatically cleaned up when the referenced object is garbage collected, but note they're not iterable and don't have `.size`.

```typescript
const privateData = new WeakMap();
const obj = {};
privateData.set(obj, 'secret');

const ref = new WeakRef(obj);
console.log(ref.deref()); // Returns obj or undefined if GC'd
```

**Common interview trap:** Thinking WeakMap prevents garbage collection—it actually enables it by not holding strong references.

answer.ru:
### WeakMap и WeakRef для управления памятью

WeakMap содержит слабые ссылки на ключи (позволяя сборке мусора, когда нет других ссылок) и полезен для хранения приватных данных. WeakRef создаёт явные слабые ссылки на объекты. Используйте их, когда данные должны быть автоматически очищены при сборке мусора, но учтите, что они не итерируемы и не имеют `.size`.

```typescript
const privateData = new WeakMap();
const obj = {};
privateData.set(obj, 'secret');

const ref = new WeakRef(obj);
console.log(ref.deref()); // Returns obj или undefined если собран GC
```

**Типичная ошибка:** Думать, что WeakMap предотвращает сборку мусора—на самом деле она её включает, не держа сильных ссылок.

answer.en:
### AbortController — Shared Signals, Timeout API, and Custom Operations

```javascript
// --- Cancelling multiple requests with one signal ---
async function loadDashboard(userId) {
  const controller = new AbortController();
  const { signal } = controller;

  // Clean up: cancel all requests if component unmounts
  const cleanup = () => controller.abort('User navigated away');

  try {
    const [user, posts, settings] = await Promise.all([
      fetch(`/api/users/${userId}`, { signal }).then(r => r.json()),
      fetch(`/api/users/${userId}/posts`, { signal }).then(r => r.json()),
      fetch(`/api/settings`, { signal }).then(r => r.json()),
    ]);
    return { user, posts, settings };
  } catch (err) {
    if (err.name === 'AbortError') {
      console.log('Dashboard load cancelled:', signal.reason);
      return null;
    }
    throw err;
  } finally {
    // unregister cleanup if everything succeeded
  }

  return cleanup; // caller can call this to cancel
}

// --- AbortSignal.timeout (Node 17+, browsers 2023) ---
try {
  const response = await fetch('/api/slow', {
    signal: AbortSignal.timeout(5000) // auto-abort after 5 seconds
  });
  const data = await response.json();
} catch (err) {
  if (err.name === 'TimeoutError') console.log('Request timed out');
  else throw err;
}

// --- Custom async operation that respects AbortSignal ---
function delay(ms, signal) {
  return new Promise((resolve, reject) => {
    if (signal?.aborted) return reject(signal.reason);

    const timer = setTimeout(resolve, ms);

    signal?.addEventListener('abort', () => {
      clearTimeout(timer);
      reject(signal.reason);
    }, { once: true });
  });
}

const ctrl = new AbortController();
delay(10000, ctrl.signal)
  .then(() => console.log('done'))
  .catch(err => console.log('cancelled:', err));

setTimeout(() => ctrl.abort('too slow'), 2000);
// 'cancelled: too slow' after 2 seconds instead of waiting 10
```

**Common interview trap:** The `abort()` call itself is synchronous — it sets `signal.aborted = true` and dispatches the `abort` event. But the fetch still has pending network I/O; it rejects only when the browser cancels the underlying request. Also, you can pass an `abort reason` to `controller.abort(reason)` (available as `signal.reason`) — useful for distinguishing timeout vs user cancellation vs navigation.

answer.ru:
### AbortController — Общие сигналы, Timeout API и пользовательские операции

```javascript
// --- Отмена нескольких запросов одним сигналом ---
async function loadDashboard(userId) {
  const controller = new AbortController();
  const { signal } = controller;

  // Очистка: отменить все запросы если компонент размонтирован
  const cleanup = () => controller.abort('Пользователь покинул страницу');

  try {
    const [user, posts, settings] = await Promise.all([
      fetch(`/api/users/${userId}`, { signal }).then(r => r.json()),
      fetch(`/api/users/${userId}/posts`, { signal }).then(r => r.json()),
      fetch(`/api/settings`, { signal }).then(r => r.json()),
    ]);
    return { user, posts, settings };
  } catch (err) {
    if (err.name === 'AbortError') {
      console.log('Загрузка дашборда отменена:', signal.reason);
      return null;
    }
    throw err;
  }

  return cleanup; // вызывающий может вызвать это для отмены
}

// --- AbortSignal.timeout (Node 17+, браузеры 2023) ---
try {
  const response = await fetch('/api/slow', {
    signal: AbortSignal.timeout(5000) // авто-отмена через 5 секунд
  });
  const data = await response.json();
} catch (err) {
  if (err.name === 'TimeoutError') console.log('Запрос превысил время');
  else throw err;
}

// --- Пользовательская async-операция, учитывающая AbortSignal ---
function delay(ms, signal) {
  return new Promise((resolve, reject) => {
    if (signal?.aborted) return reject(signal.reason);

    const timer = setTimeout(resolve, ms);

    signal?.addEventListener('abort', () => {
      clearTimeout(timer);
      reject(signal.reason);
    }, { once: true });
  });
}

const ctrl = new AbortController();
delay(10000, ctrl.signal)
  .then(() => console.log('выполнено'))
  .catch(err => console.log('отменено:', err));

setTimeout(() => ctrl.abort('слишком медленно'), 2000);
// 'отменено: слишком медленно' через 2 секунды вместо ожидания 10
```

**Типичная ошибка на интервью:** Вызов `abort()` сам по себе синхронный — он устанавливает `signal.aborted = true` и диспатчит событие `abort`. Но у fetch ещё есть ожидающий сетевой I/O; он отклоняется только когда браузер отменяет базовый запрос. Также можно передать причину отмены в `controller.abort(reason)` (доступна как `signal.reason`) — полезно для различения таймаута, действия пользователя и навигации.

answer.en:
### Microtasks — Nested Scheduling and Starvation Risk

Microtasks that schedule more microtasks run **before** the event loop returns to the task queue. Understanding this prevents subtle bugs.

```javascript
// --- Nested microtask scheduling ---
Promise.resolve()
  .then(() => {
    console.log('A'); // microtask 1
    Promise.resolve().then(() => console.log('B')); // adds to queue
    Promise.resolve().then(() => console.log('C')); // adds to queue
  })
  .then(() => console.log('D')); // chained — runs after A+B+C

setTimeout(() => console.log('E'), 0); // macrotask

// Output: A, B, C, D, E
// Why D before E? D is in the microtask queue (Promise chain),
// so it runs before the macrotask E

// --- The starvation trap ---
function scheduleMicrotask(fn) {
  return Promise.resolve().then(fn);
}

// DANGEROUS: schedules itself indefinitely as microtasks
// The task queue (setTimeout callbacks, user events) NEVER gets to run
let count = 0;
function starve() {
  count++;
  if (count < 5) scheduleMicrotask(starve); // safe here, bounded
  else console.log('done', count);
}
starve();
setTimeout(() => console.log('setTimeout ran'), 0);
// Output: done 5, setTimeout ran
// If count limit were removed: setTimeout would never run

// --- MutationObserver is also a microtask ---
const obs = new MutationObserver(() => console.log('mutation microtask'));
obs.observe(document.body, { childList: true });
document.body.appendChild(document.createElement('div'));
Promise.resolve().then(() => console.log('promise microtask'));
// Both fire before the next macrotask; order: mutation, then promise
// (MutationObserver callbacks are checked after the current task completes)
```

**Common interview trap:** Chained `.then()` callbacks (`.then().then()`) don't all run "at once" — each `.then()` schedules a **new** microtask when the previous one resolves. So a chain of 3 `.then()` adds 3 microtasks to the queue sequentially, not simultaneously. This is why Promise chains can interleave with other microtasks queued between them.

answer.ru:
### Микротаски — Вложенное планирование и риск голодания

Микротаски, которые планируют ещё микротаски, выполняются **до** того как event loop вернётся к очереди задач. Понимание этого предотвращает тонкие баги.

```javascript
// --- Вложенное планирование микротасок ---
Promise.resolve()
  .then(() => {
    console.log('A'); // microtask 1
    Promise.resolve().then(() => console.log('B')); // добавляется в очередь
    Promise.resolve().then(() => console.log('C')); // добавляется в очередь
  })
  .then(() => console.log('D')); // цепочка — выполняется после A+B+C

setTimeout(() => console.log('E'), 0); // макротаска

// Вывод: A, B, C, D, E
// Почему D раньше E? D находится в очереди микротасок (цепочка Promise),
// поэтому выполняется до макротаски E

// --- Ловушка голодания ---
function scheduleMicrotask(fn) {
  return Promise.resolve().then(fn);
}

// ОПАСНО: планирует себя бесконечно как микротаски
// Очередь задач (setTimeout callbacks, события пользователя) НИКОГДА не выполняется
let count = 0;
function starve() {
  count++;
  if (count < 5) scheduleMicrotask(starve); // безопасно здесь, ограниченно
  else console.log('готово', count);
}
starve();
setTimeout(() => console.log('setTimeout выполнен'), 0);
// Вывод: готово 5, setTimeout выполнен
// Без ограничения count: setTimeout никогда не выполнился бы

// --- MutationObserver тоже является микротаской ---
const obs = new MutationObserver(() => console.log('mutation microtask'));
obs.observe(document.body, { childList: true });
document.body.appendChild(document.createElement('div'));
Promise.resolve().then(() => console.log('promise microtask'));
// Оба выполняются до следующей макротаски; порядок: mutation, затем promise
```

**Типичная ошибка на интервью:** Цепочки `.then()` (`.then().then()`) не выполняются «одновременно» — каждый `.then()` планирует **новую** микротаску когда предыдущая resolves. Поэтому цепочка из 3 `.then()` добавляет 3 микротаски в очередь последовательно, а не одновременно. Вот почему цепочки Promise могут чередоваться с другими микротасками, поставленными в очередь между ними.

answer.en:
### Async Generators — Error Propagation and Cleanup

```javascript
// --- Error handling: throw() from outside ---
function* syncGen() {
  try {
    yield 1;
    yield 2;
    yield 3;
  } catch (e) {
    console.log('caught inside generator:', e.message);
    yield 99; // can yield after catching
  }
}

const gen = syncGen();
console.log(gen.next().value); // 1
console.log(gen.throw(new Error('external throw')).value); // caught inside generator: external throw → 99
console.log(gen.next()); // { value: undefined, done: true }

// --- Async generator with proper cleanup ---
async function* streamFromServer(endpoint, signal) {
  const response = await fetch(endpoint, { signal });
  const reader = response.body.getReader();

  try {
    while (true) {
      const { value, done } = await reader.read();
      if (done) break;
      yield new TextDecoder().decode(value);
    }
  } finally {
    // Runs when: loop ends normally, break, return(), or throw()
    reader.releaseLock();
    console.log('Stream reader released');
  }
}

const controller = new AbortController();
const stream = streamFromServer('/sse', controller.signal);

for await (const chunk of stream) {
  console.log(chunk);
  if (chunk.includes('END')) break; // triggers finally in the generator
}

// --- Composing async generators ---
async function* map(iterable, fn) {
  for await (const item of iterable) {
    yield fn(item);
  }
}

async function* filter(iterable, predicate) {
  for await (const item of iterable) {
    if (predicate(item)) yield item;
  }
}

// Pipeline: transform a stream
const processed = filter(
  map(streamFromServer('/data', controller.signal), line => line.trim()),
  line => line.length > 0
);

for await (const line of processed) {
  console.log(line);
}
```

**Common interview trap:** When you `break` out of a `for await...of` loop early, the runtime calls `.return()` on the async generator. This triggers the `finally` block. If you **don't** use `try/finally`, resources (open connections, readers, file handles) won't be released. The `finally` block in async generators is the correct place for cleanup — not `.return()` handlers.

