### Proxy — Все 13 ловушек: за пределами get и set

Proxy может перехватывать 13 различных фундаментальных операций над объектами.

```javascript
const handler = {
  // Чтение свойств
  get(target, prop, receiver) {
    if (prop === 'secret') throw new Error('Доступ запрещён');
    return Reflect.get(target, prop, receiver);
  },

  // Запись свойств
  set(target, prop, value, receiver) {
    if (typeof value !== typeof target[prop] && target[prop] !== undefined) {
      throw new TypeError(`Несоответствие типа для ${String(prop)}`);
    }
    return Reflect.set(target, prop, value, receiver);
  },

  // Оператор 'in'
  has(target, prop) {
    if (prop === 'secret') return false; // скрываем от проверок 'in'
    return Reflect.has(target, prop);
  },

  // Оператор delete
  deleteProperty(target, prop) {
    if (prop === 'id') throw new Error('Нельзя удалить id');
    return Reflect.deleteProperty(target, prop);
  },

  // Object.keys(), Object.getOwnPropertyNames()
  ownKeys(target) {
    return Reflect.ownKeys(target).filter(k => k !== 'secret');
  }
};

const obj = new Proxy({ id: 1, name: 'Alice', secret: 'pw123' }, handler);

console.log(obj.name);         // 'Alice'
console.log('secret' in obj); // false — ловушка has
console.log(Object.keys(obj)); // ['id', 'name'] — secret скрыт
// delete obj.id;              // Error: Нельзя удалить id
// obj.name = 123;             // TypeError: Несоответствие типа для name

// --- Ловушка apply: перехват вызовов функции ---
function sum(a, b) { return a + b; }
const loggedSum = new Proxy(sum, {
  apply(target, thisArg, args) {
    console.log(`sum(${args.join(', ')}) вызван`);
    return Reflect.apply(target, thisArg, args);
  }
});
console.log(loggedSum(3, 4)); // лог: sum(3, 4) вызван → 7

// --- Ловушка construct: перехват new ---
class Point {
  constructor(x, y) { this.x = x; this.y = y; }
}
const SafePoint = new Proxy(Point, {
  construct(target, args) {
    if (args.some(n => typeof n !== 'number')) throw new TypeError('Координаты должны быть числами');
    return Reflect.construct(target, args);
  }
});
new SafePoint(1, 2); // OK
// new SafePoint('a', 2); // TypeError

// --- Отзываемый Proxy: для временного доступа ---
const { proxy, revoke } = Proxy.revocable({ data: 'секрет' }, {});
console.log(proxy.data); // 'секрет'
revoke();
// proxy.data; // TypeError: Cannot perform 'get' on a proxy that has been revoked
```

**Типичная ошибка на интервью:** Параметр `receiver` в ловушках `get` и `set` критически важен при работе с getter'ами, использующими `this`. Если вызвать `Reflect.get(target, prop)` без передачи `receiver`, любой getter на `target`, использующий `this`, получит `target` как `this`, а не proxy — это ломает паттерны где подклассы проксируют свойства родительского класса.

