### WeakMap — Приватные данные класса без полей #

До приватных полей класса ES2022 (`#field`), WeakMap был идиоматическим способом хранения по-настоящему приватных данных на экземпляр.

```javascript
// --- Приватные данные с WeakMap (паттерн до ES2022) ---
const _private = new WeakMap();

class BankAccount {
  constructor(owner, balance) {
    // Приватное состояние хранится в WeakMap, не на экземпляре
    _private.set(this, { balance, transactions: [] });
    this.owner = owner; // публичное
  }

  deposit(amount) {
    const priv = _private.get(this);
    priv.balance += amount;
    priv.transactions.push({ type: 'deposit', amount, date: Date.now() });
  }

  getBalance() {
    return _private.get(this).balance;
  }

  getHistory() {
    return [..._private.get(this).transactions];
  }
}

const acc = new BankAccount('Alice', 1000);
acc.deposit(500);
console.log(acc.getBalance()); // 1500
// acc._private — undefined: нет доступа снаружи
// JSON.stringify(acc) — {"owner": "Alice"}: баланс не сериализуется

// --- Современный эквивалент с полями # ---
class ModernBankAccount {
  #balance;
  #transactions = [];

  constructor(owner, balance) {
    this.owner = owner;
    this.#balance = balance;
  }
  deposit(amount) {
    this.#balance += amount;
    this.#transactions.push({ amount, date: Date.now() });
  }
  getBalance() { return this.#balance; }
}

// --- WeakSet: отслеживание членства без утечек памяти ---
const seen = new WeakSet();

function processOnce(obj) {
  if (seen.has(obj)) {
    console.log('Уже обработан, пропуск');
    return;
  }
  seen.add(obj);
  // ... обработка
}

let item = { id: 42 };
processOnce(item); // обработан
processOnce(item); // Уже обработан, пропуск
item = null; // WeakSet не препятствует GC — item собирается
```

**Типичная ошибка на интервью:** WeakMap vs Map для приватных данных: критическое отличие — память. С `Map` экземпляры хранящиеся как ключи никогда не будут GC даже после того как все другие ссылки исчезнут — классическая утечка памяти. С WeakMap когда экземпляр больше не referenced нигде, и ключ и связанные приватные данные собираются сборщиком мусора. В этом весь смысл.

