### Делегирование генераторов — yield* и составные последовательности

`yield*` делегирует любому итерируемому — другому генератору, массиву, строке или Set.

```javascript
// --- Базовое делегирование yield* ---
function* numbers() { yield 1; yield 2; }
function* letters() { yield 'a'; yield 'b'; }

function* combined() {
  yield* numbers(); // делегирует: выдаёт 1, 2
  yield* letters(); // делегирует: выдаёт 'a', 'b'
  yield* [10, 20];  // работает и с обычными массивами
}

console.log([...combined()]); // [1, 2, 'a', 'b', 10, 20]

// --- yield* передаёт возвращаемое значение ---
function* inner() {
  yield 1;
  yield 2;
  return 'inner done'; // возвращаемое значение, не yield
}

function* outer() {
  const result = yield* inner(); // result получает возвращаемое значение
  console.log('inner вернул:', result); // 'inner done'
  yield 3;
}

console.log([...outer()]); // [1, 2, 3] — 'inner done' НЕ в последовательности

// --- Разворачивание произвольной глубины с генераторами ---
function* flatten(iterable) {
  for (const item of iterable) {
    if (item != null && typeof item[Symbol.iterator] === 'function' && typeof item !== 'string') {
      yield* flatten(item);
    } else {
      yield item;
    }
  }
}

const nested = [1, [2, [3, [4]], 5], 6];
console.log([...flatten(nested)]); // [1, 2, 3, 4, 5, 6]

// --- Составной ленивый конвейер ---
function* range(start, end) {
  for (let i = start; i <= end; i++) yield i;
}

function* take(n, iterable) {
  let count = 0;
  for (const item of iterable) {
    if (count++ >= n) break;
    yield item;
  }
}

function* mapGen(fn, iterable) {
  for (const item of iterable) yield fn(item);
}

function* filterGen(pred, iterable) {
  for (const item of iterable) if (pred(item)) yield item;
}

// Ленивый: вычисляет только нужные значения
const result = take(3,
  filterGen(x => x % 2 === 0,
    mapGen(x => x * x,
      range(1, 100)
    )
  )
);

console.log([...result]); // [4, 16, 36] — вычислено только необходимое
```

**Типичная ошибка на интервью:** `yield*` делегирует **итерацию**, а не возвращаемое значение. Возвращаемое значение внутреннего генератора захватывается как значение выражения `yield*`, но НЕ испускается как yielded элемент внешнему потребителю. Многие разработчики ожидают что `yield* gen()` передаст `return 'value'` внутреннего генератора в последовательность — это не так.

