### Proxy — Observable / Reactive Store

One of the most practical uses of Proxy is building reactive data stores that notify subscribers when data changes.

```javascript
function createStore(initialState) {
  const subscribers = new Map(); // property name → Set of callbacks

  function notify(prop, newValue, oldValue) {
    const callbacks = subscribers.get(prop);
    if (callbacks) callbacks.forEach(fn => fn(newValue, oldValue));
    // Also notify wildcard listeners
    const wildcards = subscribers.get('*');
    if (wildcards) wildcards.forEach(fn => fn(prop, newValue, oldValue));
  }

  const proxy = new Proxy({ ...initialState }, {
    set(target, prop, value, receiver) {
      const oldValue = target[prop];
      const result = Reflect.set(target, prop, value, receiver);
      if (result && oldValue !== value) {
        notify(String(prop), value, oldValue);
      }
      return result;
    },
    deleteProperty(target, prop) {
      const oldValue = target[prop];
      const result = Reflect.deleteProperty(target, prop);
      if (result) notify(String(prop), undefined, oldValue);
      return result;
    }
  });

  return {
    state: proxy,
    subscribe(prop, callback) {
      if (!subscribers.has(prop)) subscribers.set(prop, new Set());
      subscribers.get(prop).add(callback);
      return () => subscribers.get(prop).delete(callback); // unsubscribe
    }
  };
}

const { state, subscribe } = createStore({ count: 0, name: 'Alice' });

const unsubCount = subscribe('count', (newVal, oldVal) => {
  console.log(`count changed: ${oldVal} → ${newVal}`);
});

subscribe('*', (prop, newVal) => {
  console.log(`any change: ${prop} = ${newVal}`);
});

state.count = 1; // count changed: 0 → 1 / any change: count = 1
state.count = 2; // count changed: 1 → 2 / any change: count = 2
state.name = 'Bob'; // any change: name = Bob

unsubCount(); // stop listening to count
state.count = 3; // only wildcard fires now: any change: count = 3
```

**Common interview trap:** The `Reflect.set(target, prop, value, receiver)` call must include the `receiver` parameter if the target object has any setters defined with `Object.defineProperty`. Without `receiver`, the setter's `this` would be `target` (the raw object) instead of the `proxy`. This breaks patterns where a setter on a parent class needs to call through to the proxy.

