### WeakRef + FinalizationRegistry — Опциональное кэширование без утечек памяти

```javascript
// --- WeakRef: хранит ссылку которая не предотвращает GC ---
let largeData = { content: new Array(100000).fill('data') };
const weakRef = new WeakRef(largeData);

console.log(weakRef.deref()?.content.length); // 100000

largeData = null; // убираем сильную ссылку
// После выполнения GC (неопределённый момент):
// weakRef.deref() возвращает undefined

// --- FinalizationRegistry: уведомление когда объект собирается GC ---
const registry = new FinalizationRegistry((heldValue) => {
  console.log(`Объект связанный с "${heldValue}" был собран сборщиком мусора`);
});

let obj = { id: 1 };
registry.register(obj, 'токен-очистки');
obj = null; // теперь доступен для GC
// Со временем: 'Объект связанный с "токен-очистки" был собран сборщиком мусора'

// --- Практически: опциональный кэш в памяти без утечек ---
class OptionalCache {
  #cache = new Map();
  #registry;

  constructor() {
    this.#registry = new FinalizationRegistry((key) => {
      this.#cache.delete(key);
      console.log(`Запись кэша для "${key}" вытеснена GC`);
    });
  }

  set(key, value) {
    this.#cache.set(key, new WeakRef(value));
    this.#registry.register(value, key);
  }

  get(key) {
    const ref = this.#cache.get(key);
    if (!ref) return undefined;
    const value = ref.deref();
    if (!value) {
      this.#cache.delete(key); // очищаем устаревшую запись
      return undefined;
    }
    return value;
  }
}

const cache = new OptionalCache();
let user = { id: 42, name: 'Alice' };
cache.set('user:42', user);

console.log(cache.get('user:42')?.name); // 'Alice'
user = null; // GC может вытеснить; cache.get('user:42') может вернуть undefined
```

**Типичная ошибка на интервью:** `WeakRef.deref()` всегда возвращает `undefined` если объект был собран GC — никогда исходную ссылку. **Нужно** проверить возвращаемое значение перед использованием. Также, колбэк FinalizationRegistry вызывается в отдельной микротаске после GC, не синхронно, и тайминг недетерминирован. Никогда не полагайтесь на него для критической логики — используйте только для оппортунистической очистки.

