      return await fn(signal);
    } catch (err) {
      if (err.name === 'AbortError') throw err; // не повторяем при отмене
      if (attempt === retries) throw err;

      // Отменяемая задержка между попытками
      await new Promise((resolve, reject) => {
        const timer = setTimeout(resolve, delay);
        signal?.addEventListener('abort', () => {
          clearTimeout(timer);
          reject(signal.reason);
        }, { once: true });
      });
    }
  }
}

const controller = new AbortController();

retryWithAbort(
  (signal) => fetch('/api/flaky', { signal }).then(r => r.json()),
  { retries: 3, delay: 2000, signal: controller.signal }
).then(console.log).catch(err => console.log('Ошибка:', err.message));

// Отменяем снаружи через 5 секунд:
