const timeout = AbortSignal.timeout(10000);
const combined = AbortSignal.any([userCancel.signal, timeout]);

fetch('/api/data', { signal: combined })
  .then(r => r.json())
  .then(console.log)
  .catch(err => {
    if (err.name === 'TimeoutError') console.log('Таймаут через 10с');
    else if (err.name === 'AbortError') console.log('Пользователь отменил');
