### Proxy — Function Proxies and the Membrane Pattern

Proxying functions with the `apply` trap enables middleware-style wrapping without modifying the original function.

```javascript
// --- apply trap: intercept function calls ---
function createLogger(fn, name = fn.name) {
  return new Proxy(fn, {
    apply(target, thisArg, args) {
      console.log(`[CALL] ${name}(${args.map(JSON.stringify).join(', ')})`);
      const start = Date.now();
      try {
        const result = Reflect.apply(target, thisArg, args);
        console.log(`[DONE] ${name} → ${JSON.stringify(result)} (${Date.now() - start}ms)`);
        return result;
      } catch (err) {
        console.log(`[FAIL] ${name} threw: ${err.message}`);
        throw err;
      }
    }
  });
}

function add(a, b) { return a + b; }
const loggedAdd = createLogger(add);

console.log(loggedAdd(3, 4));
// [CALL] add(3, 4)
// [DONE] add → 7 (0ms)
// 7

// --- construct trap: intercept new ---
function createSingleton(Class) {
  let instance = null;
  return new Proxy(Class, {
    construct(target, args) {
      if (!instance) instance = Reflect.construct(target, args);
      return instance;
    }
  });
}

class Database {
  constructor(url) { this.url = url; }
}

const SingletonDB = createSingleton(Database);
const db1 = new SingletonDB('postgres://localhost/app');
const db2 = new SingletonDB('postgres://other/db');
console.log(db1 === db2); // true — same instance returned both times
console.log(db1.url);     // 'postgres://localhost/app'

// --- Membrane pattern: secure cross-boundary access ---
// A membrane wraps an object graph so that all objects crossing the boundary
// are also proxied — prevents reference leaks
function createMembrane(target) {
  const wrapped = new WeakMap();

  function wrap(obj) {
    if (obj === null || typeof obj !== 'object' && typeof obj !== 'function') return obj;
    if (wrapped.has(obj)) return wrapped.get(obj);

    const proxy = new Proxy(obj, {
      get(t, prop, receiver) {
        return wrap(Reflect.get(t, prop, receiver)); // wrap returned values too
      },
      set(t, prop, value, receiver) {
        return Reflect.set(t, prop, value, receiver);
      }
    });
    wrapped.set(obj, proxy);
    return proxy;
  }

  return wrap(target);
}
```

**Common interview trap:** The `apply` trap only fires when the proxy itself is called as a function — not when a method on a proxied object is called. To intercept method calls, you need a `get` trap that intercepts property access and returns a new `apply`-trapped proxy for the method. This is the core of the membrane pattern.

answer.ru:
### Proxy — Прокси функций и паттерн Membrane

Проксирование функций с помощью ловушки `apply` позволяет создавать middleware-обёртки без изменения исходной функции.

```javascript
// --- Ловушка apply: перехват вызовов функции ---
function createLogger(fn, name = fn.name) {
  return new Proxy(fn, {
    apply(target, thisArg, args) {
      console.log(`[ВЫЗОВ] ${name}(${args.map(JSON.stringify).join(', ')})`);
      const start = Date.now();
      try {
        const result = Reflect.apply(target, thisArg, args);
        console.log(`[ГОТОВО] ${name} → ${JSON.stringify(result)} (${Date.now() - start}мс)`);
        return result;
      } catch (err) {
        console.log(`[ОШИБКА] ${name} бросил: ${err.message}`);
        throw err;
      }
    }
  });
}

function add(a, b) { return a + b; }
const loggedAdd = createLogger(add);

console.log(loggedAdd(3, 4));
// [ВЫЗОВ] add(3, 4)
// [ГОТОВО] add → 7 (0мс)
// 7

// --- Ловушка construct: перехват new ---
function createSingleton(Class) {
  let instance = null;
  return new Proxy(Class, {
    construct(target, args) {
      if (!instance) instance = Reflect.construct(target, args);
      return instance;
    }
  });
}

class Database {
  constructor(url) { this.url = url; }
}

const SingletonDB = createSingleton(Database);
const db1 = new SingletonDB('postgres://localhost/app');
const db2 = new SingletonDB('postgres://other/db');
console.log(db1 === db2); // true — возвращается тот же экземпляр
console.log(db1.url);     // 'postgres://localhost/app'

// --- Паттерн Membrane: безопасный доступ через границу ---
// Membrane оборачивает граф объектов так, что все объекты пересекающие
// границу тоже проксированы — предотвращает утечки ссылок
function createMembrane(target) {
  const wrapped = new WeakMap();

  function wrap(obj) {
    if (obj === null || typeof obj !== 'object' && typeof obj !== 'function') return obj;
    if (wrapped.has(obj)) return wrapped.get(obj);

    const proxy = new Proxy(obj, {
      get(t, prop, receiver) {
        return wrap(Reflect.get(t, prop, receiver)); // оборачиваем возвращаемые значения
      },
      set(t, prop, value, receiver) {
        return Reflect.set(t, prop, value, receiver);
      }
    });
    wrapped.set(obj, proxy);
    return proxy;
  }

  return wrap(target);
}
```

**Типичная ошибка на интервью:** Ловушка `apply` срабатывает только когда сам proxy вызывается как функция — не когда вызывается метод на проксированном объекте. Для перехвата вызовов методов нужна ловушка `get`, которая перехватывает доступ к свойствам и возвращает новый proxy с ловушкой `apply` для метода. Это и есть суть паттерна membrane.

