answer.en:
### Proxy — Deep Reactive (Nested Object Tracking)

Shallow proxies only intercept top-level property access. Making nested objects reactive requires wrapping them on-the-fly.

```javascript
function reactive(raw, onChange) {
  // Cache proxies to avoid creating duplicates
  const proxyCache = new WeakMap();

  function wrap(value) {
    if (value === null || typeof value !== 'object') return value;
    if (proxyCache.has(value)) return proxyCache.get(value);

    const proxy = new Proxy(value, {
      get(target, prop, receiver) {
        const val = Reflect.get(target, prop, receiver);
        // Wrap nested objects too — lazy proxy creation
        return wrap(val);
      },
      set(target, prop, value, receiver) {
        const oldValue = target[prop];
        const result = Reflect.set(target, prop, value, receiver);
        if (result && oldValue !== value) {
          onChange(prop, value, oldValue);
        }
        return result;
      },
      deleteProperty(target, prop) {
        const hadProp = Reflect.has(target, prop);
        const result = Reflect.deleteProperty(target, prop);
        if (result && hadProp) onChange(prop, undefined, target[prop]);
        return result;
      }
    });

    proxyCache.set(value, proxy);
    return proxy;
  }

  return wrap(raw);
}

const state = reactive(
  { user: { name: 'Alice', address: { city: 'NYC' } } },
  (prop, newVal, oldVal) => console.log(`Changed: ${String(prop)} = ${JSON.stringify(newVal)}`)
);

console.log(state.user.name); // 'Alice'
state.user.name = 'Bob';      // Changed: name = "Bob"
state.user.address.city = 'LA'; // Changed: city = "LA" — nested change tracked!

// This is similar to how Vue 3's reactivity system works

// --- Performance note: Reflect.get must pass receiver for getters ---
class Config {
  get debug() { return this._debug ?? false; }
  set debug(v) { this._debug = v; }
}

const cfg = reactive(new Config(), console.log);
// Without receiver: getter's 'this' would be the raw target, not the proxy
// This breaks when getters call other proxied properties
```

**Common interview trap:** Without caching proxies (`proxyCache`), accessing the same nested object twice creates two different proxy instances. Code like `state.user === state.user` would return `false`, breaking identity comparisons and `WeakMap` lookups. Vue 3 uses the same `WeakMap` cache pattern to ensure proxy identity is stable.

