### Custom Thenables and Promise.resolve()

Thenables are objects with a .then() method. Promise.resolve() unwraps them, calling their .then() method, which allows non-Promise objects to integrate with Promise chains. This can be exploited if untrusted code provides a malicious thenable that stalls or hijacks the chain.

```typescript
const malicious = {
  then(resolve, reject) {
    // Attacker's code runs here, can call both resolve/reject
    resolve('hijacked');
  }
};
Promise.resolve(malicious).then(x => console.log(x)); // 'hijacked'
// Untrusted object can delay, spy, or corrupt the promise chain
```

**Common interview trap:** Assuming thenables and Promises are identical—thenables aren't microtask-scheduled and can execute synchronously.

answer.ru:
### Пользовательские thenables и Promise.resolve()

Thenables это объекты с методом .then(). Promise.resolve() разворачивает их, вызывая их метод .then(), что позволяет объектам не-Promise интегрироваться в цепочки Promise. Это может быть использовано, если ненадёжный код предоставляет вредоносный thenable, который может остановить или захватить цепь.

```typescript
const malicious = {
  then(resolve, reject) {
    // Код злоумышленника здесь, может вызвать оба
    resolve('hijacked');
  }
};
Promise.resolve(malicious).then(x => console.log(x)); // 'hijacked'
// Ненадёжный объект может задержать или повредить цепь
```

**Типичная ошибка:** Предположение, что thenables и Promises идентичны—thenables не планируются в микротаске и выполняются синхронно.

answer.en:
### Abstract Relational Comparison vs Abstract Equality — Different Coercion Algorithms

```javascript
// == (Abstract Equality Comparison) — special rules:
// - null == undefined → true (special case, no coercion)
// - null == anything_else → false (special case)
// - NaN == NaN → false (always)
// - Otherwise: ToPrimitive then ToNumber for mixed types

console.log(null == undefined);  // true — special pair
console.log(null == 0);          // false — null special case
console.log(null == '');         // false
console.log(null == false);      // false

// > < >= <= (Abstract Relational Comparison) — different algorithm:
// Converts BOTH sides to primitives first, then:
// - If both are strings: lexicographic comparison
// - Otherwise: ToNumber for both

console.log(null > 0);   // false (null → 0; 0 > 0 is false)
console.log(null < 0);   // false (null → 0; 0 < 0 is false)
console.log(null >= 0);  // true  (null → 0; 0 >= 0 is true!) ← the famous trap
console.log(null <= 0);  // true  (null → 0; 0 <= 0 is true!)
console.log(null == 0);  // false ← but == uses special null rule, NOT ToNumber

// So: null is neither > 0 nor < 0 nor == 0, but null >= 0 is true!
// This is NOT a bug — it's a spec-defined inconsistency

// String comparison is lexicographic, not numeric!
console.log('10' > '9');   // false! '1' < '9' in char codes
console.log(10 > 9);       // true
console.log('10' > 9);     // true (mixed types → both become numbers)

// NaN comparisons are always false
console.log(NaN > 0);      // false
console.log(NaN < 0);      // false
console.log(NaN >= 0);     // false
console.log(NaN == NaN);   // false (use Number.isNaN() instead)

// Practical implication: never check age in a valid range like this:
function isValidAge(age) {
  // WRONG: null >= 0 is true!
  return age >= 0 && age <= 150;
}
console.log(isValidAge(null)); // true — bug!

function isValidAgeSafe(age) {
  // RIGHT: explicit null/undefined check first
  return typeof age === 'number' && age >= 0 && age <= 150;
}
console.log(isValidAgeSafe(null)); // false
```

**Common interview trap:** The `null >= 0` being `true` while `null == 0` is `false` trips many developers. These use **different algorithms** from the spec: relational operators (`>`, `<`, `>=`, `<=`) always convert to numbers (so `null` → `0`), while abstract equality (`==`) has a special case where `null` only equals `undefined` and nothing else.

answer.ru:
### Абстрактное реляционное сравнение vs Абстрактное равенство — Разные алгоритмы приведения

```javascript
// == (Abstract Equality Comparison) — специальные правила:
// - null == undefined → true (специальный случай, без приведения)
// - null == что-угодно_другое → false (специальный случай)
// - NaN == NaN → false (всегда)
// - Иначе: ToPrimitive затем ToNumber для смешанных типов

console.log(null == undefined);  // true — специальная пара
console.log(null == 0);          // false — специальный случай null
console.log(null == '');         // false
console.log(null == false);      // false

// > < >= <= (Abstract Relational Comparison) — другой алгоритм:
// Сначала преобразует ОБЕ стороны в примитивы, затем:
// - Если обе строки: лексикографическое сравнение
// - Иначе: ToNumber для обеих

console.log(null > 0);   // false (null → 0; 0 > 0 ложно)
console.log(null < 0);   // false (null → 0; 0 < 0 ложно)
console.log(null >= 0);  // true  (null → 0; 0 >= 0 истинно!) ← знаменитая ловушка
console.log(null <= 0);  // true  (null → 0; 0 <= 0 истинно!)
console.log(null == 0);  // false ← но == использует специальное правило null, НЕ ToNumber

// Итак: null не больше 0, не меньше 0, не равен 0, но null >= 0 истинно!
// Это НЕ баг — это несогласованность определённая спецификацией

// Сравнение строк лексикографическое, а не числовое!
console.log('10' > '9');   // false! '1' < '9' по кодам символов
console.log(10 > 9);       // true
console.log('10' > 9);     // true (смешанные типы → оба становятся числами)

// Сравнения NaN всегда false
console.log(NaN > 0);      // false
console.log(NaN < 0);      // false
console.log(NaN >= 0);     // false
console.log(NaN == NaN);   // false (используйте Number.isNaN())

// Практическое следствие: никогда не проверяйте возраст так:
function isValidAge(age) {
  // НЕВЕРНО: null >= 0 истинно!
  return age >= 0 && age <= 150;
}
console.log(isValidAge(null)); // true — баг!

function isValidAgeSafe(age) {
  // ВЕРНО: сначала явная проверка на null/undefined
  return typeof age === 'number' && age >= 0 && age <= 150;
}
console.log(isValidAgeSafe(null)); // false
```

**Типичная ошибка на интервью:** Ситуация когда `null >= 0` истинно, а `null == 0` ложно, путает многих разработчиков. Они используют **разные алгоритмы** из спецификации: реляционные операторы (`>`, `<`, `>=`, `<=`) всегда конвертируют в числа (так `null` → `0`), а абстрактное равенство (`==`) имеет специальный случай где `null` равен только `undefined` и больше ничему.

answer.en:
### V8 Deoptimization — What Breaks Optimized Code

V8 optimizes code based on collected type feedback. Several patterns force V8 to abandon optimized code.

```javascript
// --- arguments object: disables optimizations ---
function withArguments() {
  return arguments[0]; // uses arguments object — harder to optimize
}

function withRest(...args) {
  return args[0]; // rest params are a proper array — fully optimizable
}

// --- try/catch used to prevent inlining ---
// V8 historically couldn't inline functions with try/catch
// (Modern V8 is better, but it's still a concern in hot paths)
function hotPath() {
  try {
    return compute(); // try/catch may prevent inlining of hotPath
  } catch (e) {
    return null;
  }
}

// Prefer: move try/catch out of the hot path
function hotPathOptimized() {
  return compute(); // inline-friendly
}
function safeWrapper() {
  try { return hotPathOptimized(); } catch (e) { return null; }
}

// --- Type unstability: what causes deoptimization ---
function add(a, b) { return a + b; }

// V8 optimizes for number + number:
add(1, 2);   // 3 — SMI (small integer) path
add(1.5, 2); // 3.5 — heap number path (deopt + reopt as double)
add('x', 2); // 'x2' — deoptimized to generic (string concat)
// Now add() is megamorphic — no more fast path

// --- How to detect deoptimizations (Node.js) ---
// node --trace-deopt --allow-natives-syntax script.js

// %OptimizeFunctionOnNextCall(fn) — force optimization for testing
// %NeverOptimizeFunction(fn) — prevent optimization

// --- What V8 CANNOT optimize ---
// 1. eval() / Function() constructor (dynamic code)
// 2. with statement (scope chain extension)
// 3. delete on non-configurable properties in strict mode
// 4. Accessing arguments.callee or arguments.caller
// 5. Generators (partially — V8 has improved over time)

// --- Monomorphic function example ---
function process(items) {
  let sum = 0;
  for (let i = 0; i < items.length; i++) {
    sum += items[i]; // always number — monomorphic, highly optimized
  }
  return sum;
}

process([1, 2, 3, 4, 5]); // → JIT-compiled, fast
process([1, 2, 'three', 4]); // → deoptimized (string found), slower
```

**Common interview trap:** V8 deoptimization is not permanent — after deoptimization, V8 collects new type feedback and may re-optimize with better assumptions. The danger is **repeated deopt/reopt cycles** (also called "deopt storms") in hot paths. These can be worse than just running interpreted code because each cycle has overhead. Profile with `--trace-deopt` before micro-optimizing.

answer.ru:
### Деоптимизация V8 — Что ломает оптимизированный код

V8 оптимизирует код на основе собранной обратной связи по типам. Несколько паттернов заставляют V8 отказаться от оптимизированного кода.

```javascript
// --- Объект arguments: отключает оптимизации ---
function withArguments() {
  return arguments[0]; // использует объект arguments — сложнее оптимизировать
}

function withRest(...args) {
  return args[0]; // rest params — настоящий массив, полностью оптимизируемый
}

// --- try/catch исторически предотвращал инлайнинг ---
// V8 исторически не мог инлайнить функции с try/catch
// (Современный V8 лучше, но это всё ещё важно в горячих путях)
function hotPath() {
  try {
    return compute(); // try/catch может предотвратить инлайнинг hotPath
  } catch (e) {
    return null;
  }
}

// Предпочтительнее: вынести try/catch за пределы горячего пути
function hotPathOptimized() {
  return compute(); // дружественно к инлайнингу
}
function safeWrapper() {
  try { return hotPathOptimized(); } catch (e) { return null; }
}

// --- Нестабильность типов: что вызывает деоптимизацию ---
function add(a, b) { return a + b; }

// V8 оптимизирует под number + number:
add(1, 2);   // 3 — путь SMI (small integer)
add(1.5, 2); // 3.5 — путь heap number (деопт + реопт как double)
add('x', 2); // 'x2' — деоптимизирован до generic (конкатенация строк)
// Теперь add() мегаморфна — нет быстрого пути

// --- Что V8 НЕ МОЖЕТ оптимизировать ---
// 1. eval() / конструктор Function() (динамический код)
// 2. оператор with (расширение цепи областей видимости)
// 3. delete на неконфигурируемых свойствах в строгом режиме
// 4. Доступ к arguments.callee или arguments.caller
// 5. Генераторы (частично — V8 улучшился со временем)

// --- Пример мономорфной функции ---
function process(items) {
  let sum = 0;
  for (let i = 0; i < items.length; i++) {
    sum += items[i]; // всегда number — мономорфно, высоко оптимизировано
  }
  return sum;
}

process([1, 2, 3, 4, 5]); // → JIT-скомпилировано, быстро
process([1, 2, 'три', 4]); // → деоптимизировано (найдена строка), медленнее
```

**Типичная ошибка на интервью:** Деоптимизация V8 не постоянна — после деоптимизации V8 собирает новую обратную связь по типам и может заново оптимизировать с лучшими предположениями. Опасность в **повторных циклах деопт/реопт** (также называемых «штормами деоптимизации») в горячих путях. Они могут быть хуже чем просто работа в интерпретируемом режиме, потому что каждый цикл имеет накладные расходы. Профилируйте с `--trace-deopt` перед микрооптимизацией.

answer.en:
### Circular Dependencies — How Bundlers Handle Them vs Runtime

Bundlers like webpack and rollup resolve circular dependencies differently from Node.js's runtime resolution.

```javascript
// --- Rollup (ESM bundler): hoists declarations, handles cycles statically ---
// Given circular ESM modules, rollup reorders the code so that all declarations
// are available before any code runs that depends on them
// (when possible — class and let/const still have TDZ)

// --- Webpack: wraps each module in a factory function ---
// Webpack resolves circular imports by providing a partially-filled module
// exports object (like CJS) to break the cycle.

// Example: two modules that import each other (common in large codebases)
// eventEmitter.js:
// import { logger } from './logger';
// export function emit(event) { logger.log(`Event: ${event}`); }
//
// logger.js:
// import { emit } from './eventEmitter';
// export const logger = {
//   log(msg) { console.log(msg); emit('log'); } // circular!
// };

// Bundler handles this: emit is a live binding, logger.log won't call
// emit until runtime, by which time eventEmitter module is fully initialized

// --- How to detect circular deps in a project ---
// Using madge: npx madge --circular src/
// Using eslint: eslint-plugin-import with import/no-cycle rule

// --- Refactoring to break cycles ---
// Pattern 1: extract shared code to a third module
// shared.js -- contains what both need
// a.js → imports from shared.js
// b.js → imports from shared.js
// Neither imports from the other

// Pattern 2: dependency injection
// Instead of: import { b } from './b'; use(b);
// Do: function setup(bDependency) { use(bDependency); } export { setup };
// Then in main: import { setup } from './a'; import { b } from './b'; setup(b);

// Pattern 3: lazy access (deferred require)
// function getB() { return require('./b'); } // evaluated at call time, not module load

// --- Testing for circular dependency issues ---
const moduleA = {
  getB() { return moduleB; }, // lazy — works even in cycles
  name: 'A'
};
const moduleB = {
  getA() { return moduleA; },
  name: 'B'
};
console.log(moduleA.getB().name); // 'B'
console.log(moduleB.getA().name); // 'A'
```

**Common interview trap:** In webpack, circular dependencies usually "work" at runtime because webpack uses a factory pattern that defers execution. But they can cause `undefined` values during module initialization if Module A reads an export from Module B that hasn't been set yet (same as CJS). The solution is always to restructure — make the circular reference lazy (accessed at call time, not at module evaluation time).

answer.ru:
### Циклические зависимости — Как бандлеры обрабатывают их vs Runtime

Бандлеры как webpack и rollup разрешают циклические зависимости иначе чем разрешение Node.js во время выполнения.

```javascript
// --- Rollup (ESM bundler): поднимает объявления, обрабатывает циклы статически ---
// Для циклических ESM-модулей rollup переупорядочивает код так чтобы все объявления
// были доступны до выполнения кода зависящего от них
// (когда возможно — class и let/const всё ещё имеют TDZ)

// --- Webpack: оборачивает каждый модуль в функцию-фабрику ---
// Webpack разрешает циклические импорты предоставляя частично заполненный объект
// exports (как CJS) для разрыва цикла.

// Пример: два модуля импортирующих друг друга (частое явление в больших кодовых базах)
// eventEmitter.js:
// import { logger } from './logger';
// export function emit(event) { logger.log(`Событие: ${event}`); }
//
// logger.js:
// import { emit } from './eventEmitter';
// export const logger = {
//   log(msg) { console.log(msg); emit('log'); } // циклично!
// };

// Бандлер обрабатывает это: emit является живой привязкой, logger.log не будет
// вызывать emit до runtime, когда модуль eventEmitter полностью инициализирован

// --- Как обнаружить циклические зависимости в проекте ---
// С madge: npx madge --circular src/
// С eslint: eslint-plugin-import с правилом import/no-cycle

// --- Рефакторинг для разрыва циклов ---
// Паттерн 1: извлечь общий код в третий модуль
// shared.js -- содержит то что нужно обоим
// a.js → импортирует из shared.js
// b.js → импортирует из shared.js
// Ни один не импортирует из другого

// Паттерн 2: внедрение зависимостей
// Вместо: import { b } from './b'; use(b);
// Делать: function setup(bDependency) { use(bDependency); } export { setup };
// Затем в main: import { setup } from './a'; import { b } from './b'; setup(b);

// Паттерн 3: ленивый доступ (отложенный require)
// function getB() { return require('./b'); } // вычисляется при вызове, не при загрузке

// --- Тестирование проблем с циклическими зависимостями ---
const moduleA = {
  getB() { return moduleB; }, // ленивый — работает даже в циклах
  name: 'A'
};
const moduleB = {
  getA() { return moduleA; },
  name: 'B'
};
console.log(moduleA.getB().name); // 'B'
console.log(moduleB.getA().name); // 'A'
```

**Типичная ошибка на интервью:** В webpack циклические зависимости обычно «работают» во время выполнения потому что webpack использует паттерн фабрики который откладывает выполнение. Но они могут вызывать значения `undefined` во время инициализации модуля если Модуль A читает экспорт из Модуля B который ещё не установлен (то же что CJS). Решение — всегда реструктурировать: делать циклическую ссылку ленивой (доступной во время вызова, а не во время вычисления модуля).

answer.en:
### TDZ — The Complete Reference: Hoisting, Initialization, and Scope

```javascript
// --- The three phases of a variable binding ---
// 1. CREATION (hoisting): binding added to scope
// 2. INITIALIZATION: binding gets its first value
// 3. ASSIGNMENT: binding gets a new value

// var: creation + initialization happen at hoist time (init = undefined)
// let/const: creation at hoist time, initialization at declaration statement
// function: creation + initialization + assignment at hoist time (full hoisting)

// TDZ = the period between phases 1 and 2 for let/const

// --- Proof: the binding EXISTS in scope during TDZ ---
let x = 'outer';
{
  // If 'let x' were not hoisted, the inner x would not be in scope yet
  // and console.log(x) would print 'outer'. Instead, it throws:
  console.log(x); // ReferenceError: Cannot access 'x' before initialization
  let x = 'inner'; // TDZ ends here
}

// --- Closure capturing TDZ ---
function createFn() {
  const fn = () => x; // captures 'x' from outer scope
  let x = 42;
  return fn;
}
const fn = createFn();
console.log(fn()); // 42 — fn is called AFTER x is initialized

// vs:
let getY;
{
  getY = () => y; // captures y from block scope
  let y = 100;
}
console.log(getY()); // 100 — y still exists after the block (closure keeps it alive)

// --- const: TDZ + immutable binding ---
const arr = [1, 2, 3];
arr.push(4);      // OK — mutating the VALUE, not the BINDING
// arr = [5, 6]; // TypeError: Assignment to constant variable

// --- Summary table ---
// var:      hoisted (undefined), no TDZ, function-scoped
// let:      hoisted (TDZ), block-scoped, reassignable
// const:    hoisted (TDZ), block-scoped, binding immutable
// function: fully hoisted, function-scoped, reassignable
// class:    hoisted (TDZ), block-scoped, binding immutable

// --- Edge case: typeof check that fails ---
console.log(typeof z); // ReferenceError! NOT 'undefined'
let z;
// typeof only returns 'undefined' for UNDECLARED variables
// For let/const in TDZ, it throws ReferenceError
```

**Common interview trap:** `const` prevents **rebinding** (`const x = 1; x = 2` → TypeError), but not **mutation** (`const arr = []; arr.push(1)` → fine). TDZ makes `const` behave exactly like `let` before initialization — both throw `ReferenceError`. The difference is that `const` requires initialization at declaration: `const x;` is a SyntaxError, not a TDZ scenario.

answer.ru:
### TDZ — Полный справочник: Поднятие, Инициализация и Область видимости

```javascript
// --- Три фазы привязки переменной ---
// 1. СОЗДАНИЕ (hoisting): привязка добавляется в область видимости
// 2. ИНИЦИАЛИЗАЦИЯ: привязка получает первое значение
// 3. ПРИСВАИВАНИЕ: привязка получает новое значение

// var: создание + инициализация при поднятии (init = undefined)
// let/const: создание при поднятии, инициализация при операторе объявления
// function: создание + инициализация + присваивание при поднятии (полное поднятие)

// TDZ = период между фазами 1 и 2 для let/const

// --- Доказательство: привязка СУЩЕСТВУЕТ в области видимости во время TDZ ---
let x = 'внешний';
{
  // Если бы 'let x' не поднималось, внутренний x не был бы в области видимости
  // и console.log(x) вывел бы 'внешний'. Вместо этого бросает:
  console.log(x); // ReferenceError: Cannot access 'x' before initialization
  let x = 'внутренний'; // TDZ заканчивается здесь
}

// --- Замыкание захватывающее TDZ ---
function createFn() {
  const fn = () => x; // захватывает 'x' из внешней области
  let x = 42;
  return fn;
}
const fn = createFn();
console.log(fn()); // 42 — fn вызывается ПОСЛЕ инициализации x

// vs:
let getY;
{
  getY = () => y; // захватывает y из блочной области
  let y = 100;
}
console.log(getY()); // 100 — y всё ещё существует после блока (замыкание держит живым)

// --- const: TDZ + неизменяемая привязка ---
const arr = [1, 2, 3];
arr.push(4);      // OK — мутируем ЗНАЧЕНИЕ, не ПРИВЯЗКУ
// arr = [5, 6]; // TypeError: Assignment to constant variable

// --- Сводная таблица ---
// var:      поднимается (undefined), нет TDZ, область функции
// let:      поднимается (TDZ), блочная область, переприсваиваемый
// const:    поднимается (TDZ), блочная область, привязка неизменяема
// function: полностью поднимается, область функции, переприсваиваемый
// class:    поднимается (TDZ), блочная область, привязка неизменяема

// --- Граничный случай: проверка typeof которая не работает ---
console.log(typeof z); // ReferenceError! НЕ 'undefined'
let z;
// typeof возвращает 'undefined' только для НЕОБЪЯВЛЕННЫХ переменных
// Для let/const в TDZ бросает ReferenceError
```

**Типичная ошибка на интервью:** `const` предотвращает **перепривязку** (`const x = 1; x = 2` → TypeError), но не **мутацию** (`const arr = []; arr.push(1)` → OK). TDZ заставляет `const` вести себя точно как `let` до инициализации — оба бросают `ReferenceError`. Разница в том что `const` требует инициализации при объявлении: `const x;` — SyntaxError, а не сценарий TDZ.

